module top_module(
input  wire clk,
input  wire rst,
output wire [3:0] count
);reg [3:0] invalid_counter;

always @(posedge clk or posedge rst)
    if (rst)
        invalid_counter <= 4'b0000;
    else
        invalid_counter <= invalid_counter + 1;

assign count = invalid_counter;

endmodule
